-- calc_client_approvals_name
-- Field: ClientApprovals.Name
-- Type: calculated | DataType: string | Returns: TEXT

CREATE OR REPLACE FUNCTION calc_client_approvals_name(p_client_approval_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT((SELECT NULLIF(client, '') FROM client_approvals WHERE client_approval_id = p_client_approval_id), '-', CASE WHEN calc_client_approvals_is_approved(p_client_approval_id) THEN ('APVD')::text ELSE ('PEND')::text END))::text;
$$ LANGUAGE sql STABLE;

-- calc_client_approvals_is_approved
-- Field: ClientApprovals.IsApproved
-- Type: calculated | DataType: boolean | Returns: BOOLEAN

CREATE OR REPLACE FUNCTION calc_client_approvals_is_approved(p_client_approval_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (NOT ((SELECT NULLIF(approved_by, '') FROM client_approvals WHERE client_approval_id = p_client_approval_id) IS NULL))::boolean;
$$ LANGUAGE sql STABLE;

