-- calc_products_name
-- Field: Products.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_products_name(p_product_id TEXT)
RETURNS TEXT AS $$
  SELECT (LOWER(REPLACE((SELECT NULLIF(sku, '') FROM products WHERE product_id = p_product_id), ' ', '-')))::text;
$$ LANGUAGE sql STABLE;

-- calc_products_profit
-- Field: Products.Profit
-- Type: calculated | DataType: number | Returns: NUMERIC

CREATE OR REPLACE FUNCTION calc_products_profit(p_product_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((COALESCE(CASE WHEN ((SELECT unit_price FROM products WHERE product_id = p_product_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT unit_price FROM products WHERE product_id = p_product_id))::numeric ELSE NULL END, 0) - COALESCE(CASE WHEN ((SELECT cost FROM products WHERE product_id = p_product_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT cost FROM products WHERE product_id = p_product_id))::numeric ELSE NULL END, 0)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_products_margin
-- Field: Products.Margin
-- Type: calculated | DataType: number | Returns: NUMERIC

CREATE OR REPLACE FUNCTION calc_products_margin(p_product_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((COALESCE(1, 0) - COALESCE(CASE WHEN ((COALESCE(CASE WHEN ((SELECT cost FROM products WHERE product_id = p_product_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT cost FROM products WHERE product_id = p_product_id))::numeric ELSE NULL END, 0) / NULLIF(COALESCE(CASE WHEN ((SELECT unit_price FROM products WHERE product_id = p_product_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT unit_price FROM products WHERE product_id = p_product_id))::numeric ELSE NULL END, 0), 0)))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((COALESCE(CASE WHEN ((SELECT cost FROM products WHERE product_id = p_product_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT cost FROM products WHERE product_id = p_product_id))::numeric ELSE NULL END, 0) / NULLIF(COALESCE(CASE WHEN ((SELECT unit_price FROM products WHERE product_id = p_product_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT unit_price FROM products WHERE product_id = p_product_id))::numeric ELSE NULL END, 0), 0)))::numeric ELSE NULL END, 0)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_products_is_high_margin
-- Field: Products.IsHighMargin
-- Type: calculated | DataType: boolean | Returns: BOOLEAN

CREATE OR REPLACE FUNCTION calc_products_is_high_margin(p_product_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_products_margin(p_product_id))::NUMERIC > 0.65)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_products_stock_quantity
-- Field: Products.StockQuantity
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_products_stock_quantity(p_product_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COALESCE(SUM((quantity)::numeric), 0) FROM inventory_adjustments WHERE product = p_product_id))::integer;
$$ LANGUAGE sql STABLE;

-- calc_products_cogs
-- Field: Products.COGS
-- Type: calculated | DataType: number | Returns: NUMERIC

CREATE OR REPLACE FUNCTION calc_products_cogs(p_product_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((COALESCE(CASE WHEN (calc_products_stock_quantity(p_product_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_products_stock_quantity(p_product_id))::numeric ELSE NULL END, 0) * COALESCE(CASE WHEN ((SELECT cost FROM products WHERE product_id = p_product_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT cost FROM products WHERE product_id = p_product_id))::numeric ELSE NULL END, 0)))::numeric;
$$ LANGUAGE sql STABLE;

