  SELECT ((calc_invoices_sub_total(p_invoice_id))::NUMERIC > 350)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_invoices_tax_amount
-- Field: Invoices.TaxAmount
-- Type: calculated | DataType: number | Returns: NUMERIC

CREATE OR REPLACE FUNCTION calc_invoices_tax_amount(p_invoice_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((COALESCE(CASE WHEN (calc_invoices_sub_total(p_invoice_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_invoices_sub_total(p_invoice_id))::numeric ELSE NULL END, 0) * COALESCE(CASE WHEN ((SELECT tax_rate FROM invoices WHERE invoice_id = p_invoice_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT tax_rate FROM invoices WHERE invoice_id = p_invoice_id))::numeric ELSE NULL END, 0)))::numeric;
$$ LANGUAGE sql STABLE;

