-- Type: calculated | DataType: number | Returns: NUMERIC

CREATE OR REPLACE FUNCTION calc_invoices_invoice_total(p_invoice_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((COALESCE(CASE WHEN (calc_invoices_sub_total(p_invoice_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_invoices_sub_total(p_invoice_id))::numeric ELSE NULL END, 0) + COALESCE(CASE WHEN (calc_invoices_tax_amount(p_invoice_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_invoices_tax_amount(p_invoice_id))::numeric ELSE NULL END, 0)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_invoices_total_paid
-- Field: Invoices.TotalPaid
-- Type: aggregation | DataType: number | Returns: NUMERIC

CREATE OR REPLACE FUNCTION calc_invoices_total_paid(p_invoice_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((SELECT COALESCE(SUM((calc_payments_completed_amount(payment_id))::numeric), 0) FROM payments WHERE invoice = p_invoice_id))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_invoices_amount_due
-- Field: Invoices.AmountDue
-- Type: calculated | DataType: number | Returns: NUMERIC

CREATE OR REPLACE FUNCTION calc_invoices_amount_due(p_invoice_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (ROUND(((COALESCE(CASE WHEN (calc_invoices_invoice_total(p_invoice_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_invoices_invoice_total(p_invoice_id))::numeric ELSE NULL END, 0) - COALESCE(CASE WHEN (calc_invoices_total_paid(p_invoice_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_invoices_total_paid(p_invoice_id))::numeric ELSE NULL END, 0)))::NUMERIC, (2)::INTEGER))::numeric;
$$ LANGUAGE sql STABLE;

