-- Type: calculated | DataType: boolean | Returns: BOOLEAN

CREATE OR REPLACE FUNCTION calc_invoices_is_paid_in_full(p_invoice_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (CASE WHEN (calc_invoices_amount_due(p_invoice_id))::NUMERIC <= 0 THEN TRUE ELSE FALSE END)::boolean;
$$ LANGUAGE sql STABLE;

