-- calc_invoices_payment_status_label
-- Field: Invoices.PaymentStatusLabel
-- Type: calculated | DataType: string | Returns: TEXT

CREATE OR REPLACE FUNCTION calc_invoices_payment_status_label(p_invoice_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_invoices_is_paid_in_full(p_invoice_id) THEN ('Paid')::text ELSE (CASE WHEN (calc_invoices_total_paid(p_invoice_id))::NUMERIC = 0 THEN ('Unpaid')::text ELSE ('Partial')::text END)::text END)::text;
$$ LANGUAGE sql STABLE;

