  SELECT (LOWER(REPLACE(CONCAT((SELECT NULLIF(invoice, '') FROM invoice_line_items WHERE invoice_line_item_id = p_invoice_line_item_id), '-line-', (SELECT NULLIF(line_number, '') FROM invoice_line_items WHERE invoice_line_item_id = p_invoice_line_item_id)), ' ', '-')))::text;
$$ LANGUAGE sql STABLE;

-- calc_invoice_line_items_pre_discount
-- Field: InvoiceLineItems.PreDiscount
-- Type: calculated | DataType: number | Returns: NUMERIC

CREATE OR REPLACE FUNCTION calc_invoice_line_items_pre_discount(p_invoice_line_item_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((COALESCE(CASE WHEN ((SELECT quantity FROM invoice_line_items WHERE invoice_line_item_id = p_invoice_line_item_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT quantity FROM invoice_line_items WHERE invoice_line_item_id = p_invoice_line_item_id))::numeric ELSE NULL END, 0) * COALESCE(CASE WHEN (calc_invoice_line_items_unit_price(p_invoice_line_item_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_invoice_line_items_unit_price(p_invoice_line_item_id))::numeric ELSE NULL END, 0)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_invoice_line_items_discount_amount
