-- Type: calculated | DataType: number | Returns: NUMERIC

CREATE OR REPLACE FUNCTION calc_invoice_line_items_discount_amount(p_invoice_line_item_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((COALESCE(CASE WHEN (calc_invoice_line_items_pre_discount(p_invoice_line_item_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_invoice_line_items_pre_discount(p_invoice_line_item_id))::numeric ELSE NULL END, 0) * COALESCE(CASE WHEN (calc_invoice_line_items_discount_percent(p_invoice_line_item_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_invoice_line_items_discount_percent(p_invoice_line_item_id))::numeric ELSE NULL END, 0)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_invoice_line_items_sub_total
-- Field: InvoiceLineItems.SubTotal
-- Type: calculated | DataType: number | Returns: NUMERIC

CREATE OR REPLACE FUNCTION calc_invoice_line_items_sub_total(p_invoice_line_item_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((COALESCE(CASE WHEN (calc_invoice_line_items_pre_discount(p_invoice_line_item_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_invoice_line_items_pre_discount(p_invoice_line_item_id))::numeric ELSE NULL END, 0) - COALESCE(CASE WHEN (calc_invoice_line_items_discount_amount(p_invoice_line_item_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_invoice_line_items_discount_amount(p_invoice_line_item_id))::numeric ELSE NULL END, 0)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_inventory_adjustments_adjustment_name
-- Field: InventoryAdjustments.Adjustment_Name
-- Type: calculated | DataType: string | Returns: TEXT

CREATE OR REPLACE FUNCTION calc_inventory_adjustments_adjustment_name(p_inventory_adjustment_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT((SELECT NULLIF(product, '') FROM inventory_adjustments WHERE inventory_adjustment_id = p_inventory_adjustment_id), '-', LEFT(((SELECT date::timestamptz FROM inventory_adjustments WHERE inventory_adjustment_id = p_inventory_adjustment_id))::text, (10)::integer), '-qty', (SELECT quantity FROM inventory_adjustments WHERE inventory_adjustment_id = p_inventory_adjustment_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_payments_invoice_date
-- Field: Payments.InvoiceDate
-- Type: lookup | DataType: datetime | Returns: TIMESTAMPTZ
-- Lookup: OrderDate from related Invoices

CREATE OR REPLACE FUNCTION calc_payments_invoice_date(p_payment_id TEXT)
RETURNS TIMESTAMPTZ AS $$
  SELECT (SELECT order_date::timestamptz FROM invoices WHERE invoice_id = (SELECT invoice FROM payments WHERE payment_id = p_payment_id));
$$ LANGUAGE sql STABLE;

