-- calc_payments_name
-- Field: Payments.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_payments_name(p_payment_id TEXT)
RETURNS TEXT AS $$
  SELECT (LOWER(REPLACE(CONCAT((SELECT NULLIF(invoice, '') FROM payments WHERE payment_id = p_payment_id), '-pmt-', (SELECT NULLIF(payment_number, '') FROM payments WHERE payment_id = p_payment_id)), ' ', '-')))::text;
$$ LANGUAGE sql STABLE;

-- calc_payments_is_completed
-- Field: Payments.IsCompleted
-- Type: calculated | DataType: boolean | Returns: BOOLEAN

CREATE OR REPLACE FUNCTION calc_payments_is_completed(p_payment_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (CASE WHEN (SELECT NULLIF(payment_status, '') FROM payments WHERE payment_id = p_payment_id) = 'Completed' THEN TRUE ELSE FALSE END)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_payments_completed_amount
-- Field: Payments.CompletedAmount
-- Type: calculated | DataType: number | Returns: NUMERIC

CREATE OR REPLACE FUNCTION calc_payments_completed_amount(p_payment_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (CASE WHEN (SELECT NULLIF(payment_status, '') FROM payments WHERE payment_id = p_payment_id) = 'Completed' THEN ((SELECT amount FROM payments WHERE payment_id = p_payment_id))::text ELSE (0)::text END)::numeric;
$$ LANGUAGE sql STABLE;

