-- calc_addresses_name
-- Field: Addresses.Name
-- Type: calculated | DataType: string | Returns: TEXT

CREATE OR REPLACE FUNCTION calc_addresses_name(p_addresse_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT((SELECT NULLIF(address1, '') FROM addresses WHERE addresse_id = p_addresse_id), ', ', (SELECT NULLIF(city, '') FROM addresses WHERE addresse_id = p_addresse_id), ', ', (SELECT NULLIF(state, '') FROM addresses WHERE addresse_id = p_addresse_id), ' ', (SELECT NULLIF(zip, '') FROM addresses WHERE addresse_id = p_addresse_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_states_name
-- Field: States.Name
-- Type: calculated | DataType: string | Returns: TEXT

CREATE OR REPLACE FUNCTION calc_states_name(p_state_id TEXT)
RETURNS TEXT AS $$
  SELECT (LOWER(CONCAT((SELECT NULLIF(code, '') FROM states WHERE state_id = p_state_id), '-', REPLACE((SELECT NULLIF(text, '') FROM states WHERE state_id = p_state_id), ' ', '-'))))::text;
$$ LANGUAGE sql STABLE;

-- ============================================================================
-- MANY-SIDE RELATIONSHIP FUNCTIONS
-- These functions aggregate child records for many-side relationships
-- ============================================================================

-- calc_app_users_client_approvals
-- Field: AppUsers.ClientApprovals
-- Type: Many-side relationship (backref) to ClientApprovals
-- Aggregates: ClientApprovals.ClientApprovalId where ApprovedBy = parent
CREATE OR REPLACE FUNCTION calc_app_users_client_approvals(p_app_user_id TEXT)
RETURNS TEXT AS $$
  SELECT (
    SELECT STRING_AGG(client_approval_id::TEXT, ', ' ORDER BY client_approval_id)
    FROM client_approvals
    WHERE approved_by = p_app_user_id
  );
$$ LANGUAGE sql STABLE;

-- calc_clients_invoices
-- Field: Clients.Invoices
-- Type: Many-side relationship (backref) to Invoices
-- Aggregates: Invoices.InvoiceId where Client = parent

CREATE OR REPLACE FUNCTION calc_clients_invoices(p_client_id TEXT)
RETURNS TEXT AS $$
  SELECT (
    SELECT STRING_AGG(invoice_id::TEXT, ', ' ORDER BY invoice_id)
    FROM invoices
    WHERE client = p_client_id
  );
$$ LANGUAGE sql STABLE;

